7096	\begin{lemma}
7097	[The augmentation kills the first differential]
7098	  \label{lem:cech_augmentation_comp_d}
7099	  \lean{AlgebraicGeometry.cechAugmentation_comp_d,
7100	    AlgebraicGeometry.augmentation_comp_alternatingCofaceMap_objD_zero}
7101	  \uses{def:cech_augmentation}
7102	  \textit{Project-local.}
7103	  The composite of the augmentation \(\varepsilon : \mathcal{F} \to \mathcal{C}^0\) of
7104	  Definition~\ref{def:cech_augmentation} with the first {\v C}ech differential vanishes,
7105	  \[
7106	    \varepsilon \cdot d^0 \;=\; 0.
7107	  \]
7108	\end{lemma}
7109	\begin{proof}
7110	  \uses{def:cech_augmentation}
7111	  This is the standard augmented-cosimplicial identity. The differential \(d^0 = \delta^0 - \delta^1\)
7112	  is the alternating sum of the two cofaces, and naturality of the augmentation natural transformation
7113	  of the cosimplicial object intertwines \(\varepsilon\) with \(\delta^0\) and with \(\delta^1\) in the
7114	  same way; the two contributions therefore cancel.
7115	\end{proof}
